// Reads amplify_outputs.json (generated by `npx ampx sandbox` or `pipeline-deploy`)
// and writes frontend/.env.local with the values the frontend needs.
// Run after every sandbox start, since identifiers change per environment.
import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const root = resolve(here, '..');
const outputsPath = resolve(root, 'amplify_outputs.json');
const envPath = resolve(root, 'frontend/.env.local');

if (!existsSync(outputsPath)) {
  console.error(
    'amplify_outputs.json not found at repo root. Run `npx ampx sandbox` first.'
  );
  process.exit(1);
}

const outputs = JSON.parse(readFileSync(outputsPath, 'utf8'));
const auth = outputs.auth ?? {};
const custom = outputs.custom ?? {};

const required = {
  VITE_USE_AMPLIFY: 'true',
  VITE_COGNITO_USER_POOL_ID: auth.user_pool_id,
  VITE_COGNITO_USER_POOL_CLIENT_ID: auth.user_pool_client_id,
  VITE_API_URL: custom.apiUrl,
};

const missing = Object.entries(required)
  .filter(([, v]) => !v)
  .map(([k]) => k);
if (missing.length > 0) {
  console.error('amplify_outputs.json is missing keys for:', missing.join(', '));
  console.error('Expected auth.user_pool_id, auth.user_pool_client_id, custom.apiUrl');
  process.exit(1);
}

const lines = [
  '# Generated by scripts/sync-amplify-config.mjs — re-run after `npx ampx sandbox`.',
  ...Object.entries(required).map(([k, v]) => `${k}=${v}`),
  '',
];
writeFileSync(envPath, lines.join('\n'));
console.log(`Wrote ${envPath}`);
console.log(`  user pool:  ${auth.user_pool_id}`);
console.log(`  client id:  ${auth.user_pool_client_id}`);
console.log(`  api url:    ${custom.apiUrl}`);
